mapper.select:
select

from `user` bu
inner join user_org buo on bu.id = buo.user_id and buo.deleted = 0 and buo.checked = 1
inner join `org` bo on buo.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2
where bu.deleted = 0

    and bu.enabled = #{ew.enabled}


    and bu.job_number = #{ew.jobNumber}


    and bu.username = #{ew.username}


    and bu.mobile = #{ew.mobile}


    and bu.real_name = #{ew.realName}


    and bu.mail = #{ew.mail}

and bo.id = #{ew.orgId}
order by bu.modified_time desc

select
,
from `user` bu inner join third_bind_grant tbg on bu.id = tbg.user_id and tbg.deleted = 0 inner join user_org buo on bu.id = buo.user_id and buo.deleted = 0 and buo.checked = 1 inner join `org` bo on buo.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2 where bu.deleted = 0 and tbg.code = #{code}

select
,
from `user` bu inner join user_org buo on bu.id = buo.user_id and buo.deleted = 0 and buo.checked = 1 inner join `org` bo on buo.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2 where bu.deleted = 0 and bu.enabled = 1 and bu.locked = 0 and bu.account_expired = 0 and bu.credentials_expired = 0 and bu.id = #{userId}

select

    ,

from `user` bu
inner join user_org buo on bu.id = buo.user_id and buo.deleted = 0 and buo.checked = 1
inner join `org` bo on buo.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2
where bu.deleted = 0 and bu.enabled = 1 and bu.locked = 0 and bu.account_expired = 0 and bu.credentials_expired = 0

    and bu.job_number = #{ew.jobNumber}


    and bu.username = #{ew.username}


    and bu.mobile = #{ew.mobile}


    and bu.mail = #{ew.mail}


    and bu.id_card = #{ew.idCard}
